     8→import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_fab_state.dart';
     9→import 'package:baseball_detector_flutter/views/routers/app_router.dart';
    10→import 'package:baseball_detector_flutter/views/themes/color_manager.dart';
    11→import 'package:collection/collection.dart';
    12→import 'package:flutter/material.dart';
    13→import 'package:hooks_riverpod/hooks_riverpod.dart';
    14→import 'package:knowhere_configurable_camera/knowhere_configurable_camera.dart';
    15→
    16→class RecordingFab extends HookConsumerWidget {
    17→  const RecordingFab({
    18→    required this.currentSession,
    19→    required this.teamId,
    20→    required this.canSubscribe,
    21→    super.key,
    22→  });
    23→
    24→  final Session currentSession;
    25→  final String teamId;
    26→  final bool canSubscribe;
    27→
    28→  @override
    29→  Widget build(BuildContext context, WidgetRef ref) {
    30→    final showSubscriptionPage = useSubscriptionPage();
    31→    final goToSubscription = useDebounce(showSubscriptionPage);
    32→    final teamList = ref.watch(teamListControllerProvider);
    33→
    34→    final fabState = useFabState(
    35→      session: currentSession,
    36→      teamId: teamId,
    37→      canSubscribe: canSubscribe,
    38→    );
    39→
    40→    switch (fabState) {
    41→      case FabState.available:
    42→        return FloatingActionButton(
    43→          backgroundColor:
    44→              Theme.of(context).floatingActionButtonTheme.backgroundColor,
    45→          onPressed: () async {
    46→            try {
    47→              final isSupported =
    48→                  await KnowhereConfigurableCamera.getSingletonObject()
    49→                      .isSupportedDevice();
    50→
    51→              if (isSupported != true && context.mounted) {
    52→                final shouldContinue = await showDialog<bool>(
    53→                  context: context,
    54→                  barrierDismissible: false,
    55→                  builder: (context) => CustomDialog.oneMessage(
    56→                    title: context.l10n
    57→                        .session_details_page__device_unsupported_dialog_title,
    58→                    messageText: context.l10n
    59→                        .session_details_page__device_unsupported_dialog_message,
    60→                    aboveButtonText: context.l10n
    61→                        .session_details_page__device_unsupported_dialog_continue,
    62→                    belowButtonText: context.l10n
    63→                        .session_details_page__device_unsupported_dialog_cancel,
    64→                    isAbovePositive: true,
    65→                    isBelowPositive: false,
    66→                    aboveButtonAction: (dialogContext) {
    67→                      Navigator.of(dialogContext).pop(true);
    68→                    },
    69→                    belowButtonAction: (dialogContext) {
    70→                      Navigator.of(dialogContext).pop(false);
    71→                    },
    72→                  ),
    73→                );
    74→
    75→                if (shouldContinue != true) {
    76→                  return;
    77→                }
    78→              }
    79→            } catch (e) {
    80→              debugPrint('Failed to check device support: $e');
    81→            }
    82→
    83→            if (!context.mounted) return;
    84→
    85→            Navigator.of(context, rootNavigator: true).pushNamed(
    86→              AppRouter.recordingPage,
    87→              arguments: {
    88→                'sessionId': currentSession.id!,
    89→                'sessionCreatedAt': currentSession.createdAt ?? DateTime.now(),
    90→                'teamId': teamId,
    91→              },
    92→            );
    93→          },
    94→          child: const Icon(Icons.videocam_outlined),
    95→        );
    96→
    97→      case FabState.needsSubscription:
    98→        return FloatingActionButton(
    99→          backgroundColor: ColorManager.secondaryText,
   100→          onPressed: () {
   101→            if (canSubscribe) {
   102→              final teams = teamList.valueOrNull;
   103→              if (teams == null || teams.hasLeft) return;
   104→              final team = teams.right.firstWhereOrNull((t) => t.id == teamId);
