     7→import 'package:baseball_detector_flutter/data/models/ball.dart';
     8→import 'package:baseball_detector_flutter/data/models/dto/player/handedness.dart';
     9→import 'package:baseball_detector_flutter/data/models/failure/bad_request_failure.dart';
    10→import 'package:baseball_detector_flutter/data/models/player.dart';
    11→import 'package:baseball_detector_flutter/data/models/session.dart';
    12→import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
    13→import 'package:baseball_detector_flutter/providers/repository_provider.dart';
    14→import 'package:baseball_detector_flutter/utils/snack_bar.dart';
    15→import 'package:baseball_detector_flutter/views/hooks/use_operation.dart';
    16→import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';
    17→import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_session_refresh.dart';
    18→
    19→Future<void> Function({
    20→  required List<Ball> hittingBalls,
    21→  required List<Ball> pitchingBalls,
    22→}) useAIReportGeneration({
    23→  required Player? player,
    24→  required ValueNotifier<Session> currentSession,
    25→}) {
    26→  final context = useContext();
    27→  final ref = useWidgetRef();
    28→  final repository = ref.watch(repositoryProvider);
    29→  final handleOperation = useOperation<String>();
    30→
    31→  final onRefresh = useSessionRefresh(currentSession: currentSession);
    32→
    33→  return ({
    34→    required List<Ball> hittingBalls,
    35→    required List<Ball> pitchingBalls,
    36→  }) async {
    37→    final sessionId = currentSession.value.id;
    38→    final teamId = currentSession.value.teamId;
    39→
    40→    if (sessionId == null || teamId == null) return;
    41→
    42→    final hasPitchingBalls = pitchingBalls.isNotEmpty;
    43→    final hasAllPitchTypes = hasPitchingBalls &&
    44→        !pitchingBalls.any(
    45→          (ball) =>
    46→              ball.pitchType == null || ball.pitchType?.pitchType == 'none',
    47→        );
    48→
    49→    if (!hasPitchingBalls) {
    50→      context.showErrorSnackBar(
    51→        context.l10n.ai_coach_report__request_need_pitching_data,
    52→      );
    53→      return;
    54→    }
    55→
    56→    if (!hasAllPitchTypes) {
    57→      context.showErrorSnackBar(
    58→        context.l10n.ai_coach_report__request_need_pitch_type,
    59→      );
    60→      return;
    61→    }
    62→
    63→    final pitchingHand = player?.pitchingHand ?? Handedness.none;
    64→    if (pitchingHand == Handedness.none) {
    65→      context.showErrorSnackBar(
    66→        context.l10n.ai_coach_report__request_need_player_pitching_hand,
    67→      );
    68→      return;
    69→    }
    70→
    71→    final hasBirthday = player?.birthday != null;
    72→    if (!hasBirthday) {
    73→      context.showErrorSnackBar(
    74→        context.l10n.ai_coach_report__request_need_player_birthday,
    75→      );
    76→      return;
    77→    }
    78→
    79→    await handleOperation(
    80→      operation:
    81→          repository.createAIReport(teamId: teamId, sessionId: sessionId),
    82→      onSucceeded: (_) async {
    83→        await onRefresh();
    84→        return context.mounted
    85→            ? context.l10n.ai_coach_report__request_success_message
    86→            : null;
    87→      },
    88→      onFailed: (failure) async =>
    89→          context.mounted ? failure.translate(context.l10n) : null,
    90→      shouldSendErrorLog: (failure) =>
    91→          !_ignoreFailure.contains(failure.runtimeType),
    92→    );
    93→  };
    94→}
    95→
    96→// エラーログを送らない Failure
    97→const _ignoreFailure = [
    98→  PitchTypeNotTaggedForAllResourcesFailure,
    99→  PlayerBirthdayMissingFailure,
   100→  PlayerThrowHandMissingFailure,
   101→  SessionHasNoResourcesFailure,
