/// {@category Providers}
library;

// Package imports:
import 'package:collection/collection.dart';
import 'package:fimber/fimber.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/user_info.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';

part 'user_accessible_contents_controller.g.dart';

/// Controller for managing UserAccessibleContents
/// This provides centralized access to user's role-based permissions
@Riverpod(keepAlive: true)
class UserAccessibleContentsController
    extends _$UserAccessibleContentsController {
  static final _logger = FimberLog('UserAccessibleContentsController');

  @override
  UserAccessibleContents? build() {
    return null;
  }

  /// Refresh accessible contents from API
  Future<UserAccessibleContents?> refresh() async {
    final repository = ref.watch(repositoryProvider);
    final result = await repository.getAccessibleContents();
    late final UserAccessibleContents? userAccessibleContents;

    result.fold(
      (failure) {
        _logger.e('Failed to refresh accessible contents', ex: failure);
        // Log error but don't throw - keep existing contents
        userAccessibleContents = state;
      },
      (contents) {
        // contents と state が異なる場合のみ更新
        // Use DeepCollectionEquality for proper content comparison
        if (!const DeepCollectionEquality().equals(contents, state)) {
          _logger
              .i('Successfully refreshed accessible contents from repository');
          state = contents;
        }
        userAccessibleContents = state;
      },
    );

    return userAccessibleContents;
  }
}

